import{_ as t,c as o,o as r,ag as a}from"./chunks/framework.DVUBUV_u.js";const u=JSON.parse('{"title":"Traffic interception","description":"","frontmatter":{"title":"Traffic interception"},"headers":[],"relativePath":"network/traffic.md","filePath":"network/traffic.md"}'),s={name:"network/traffic.md"};function n(i,e,l,h,c,d){return r(),o("div",null,[...e[0]||(e[0]=[a('<h1 id="breakpoints-and-mock-responses" tabindex="-1">Breakpoints and mock responses <a class="header-anchor" href="#breakpoints-and-mock-responses" aria-label="Permalink to &quot;Breakpoints and mock responses&quot;">​</a></h1><p>The <strong>Network</strong> tab and <strong>Options → Network</strong> provide two interception mechanisms:</p><ul><li><strong>Breakpoint</strong> — pause an outgoing request <strong>before it hits the network</strong>, edit parameters, then continue;</li><li><strong>Mock response</strong> — return a crafted response <strong>without calling the server</strong>.</li></ul><p>Both apply only to <strong><code>fetch</code></strong> and <strong><code>XMLHttpRequest</code></strong> on the current page.</p><p>General interception limits (page context, CORS, scope) are described in <a href="/docs/network/general.html">Working with requests</a>.</p><hr><h2 id="breakpoints" tabindex="-1">Breakpoints <a class="header-anchor" href="#breakpoints" aria-label="Permalink to &quot;Breakpoints&quot;">​</a></h2><h3 id="purpose" tabindex="-1">Purpose <a class="header-anchor" href="#purpose" aria-label="Permalink to &quot;Purpose&quot;">​</a></h3><p>A breakpoint pauses an outbound request <strong>before it is sent</strong>.</p><p>When URL and method match the rule:</p><ul><li>the request is held;</li><li>the UI lets you edit parameters;</li><li>after confirmation the request continues with your changes;</li><li>or you can cancel.</li></ul><p>Interception happens after the app built the request but before native send.</p><h3 id="what-you-can-change" tabindex="-1">What you can change <a class="header-anchor" href="#what-you-can-change" aria-label="Permalink to &quot;What you can change&quot;">​</a></h3><p>Before continuing you can edit:</p><ul><li>HTTP method;</li><li>URL (scheme, host, path, query);</li><li>headers;</li><li>body.</li></ul><p>After <strong>Apply</strong> the request goes out in the modified form.</p><h3 id="where-to-configure" tabindex="-1">Where to configure <a class="header-anchor" href="#where-to-configure" aria-label="Permalink to &quot;Where to configure&quot;">​</a></h3><ul><li><strong>Network</strong> — create or adjust a breakpoint from a captured request.</li><li><strong>Options → Network → Breakpoints Requests</strong> — manage the rule list.</li></ul><h3 id="behavior" tabindex="-1">Behavior <a class="header-anchor" href="#behavior" aria-label="Permalink to &quot;Behavior&quot;">​</a></h3><p>When a request hits an active breakpoint rule the UI focuses editing:</p><ul><li>the breakpoint card opens;</li><li>the view may switch to <strong>Network</strong>;</li><li>a collapsed inspector iframe expands automatically.</li></ul><p>Until you confirm or cancel, the request stays paused.</p><h2 id="mock-responses" tabindex="-1">Mock responses <a class="header-anchor" href="#mock-responses" aria-label="Permalink to &quot;Mock responses&quot;">​</a></h2><h3 id="purpose-1" tabindex="-1">Purpose <a class="header-anchor" href="#purpose-1" aria-label="Permalink to &quot;Purpose&quot;">​</a></h3><p>Mock fully replaces a network call with a local response.</p><p>When a rule matches:</p><ul><li>no server round-trip;</li><li>a synthetic response is built;</li><li>the page receives it like a normal HTTP response.</li></ul><h3 id="what-a-mock-can-set" tabindex="-1">What a mock can set <a class="header-anchor" href="#what-a-mock-can-set" aria-label="Permalink to &quot;What a mock can set&quot;">​</a></h3><ul><li><strong>status</strong> and <strong>statusText</strong>;</li><li><strong>headers</strong>;</li><li><strong>body</strong>;</li><li><strong>delay</strong> before resolving.</li></ul><h3 id="where-to-configure-1" tabindex="-1">Where to configure <a class="header-anchor" href="#where-to-configure-1" aria-label="Permalink to &quot;Where to configure&quot;">​</a></h3><ul><li><strong>Network</strong> — create or adjust from a request row.</li><li><strong>Options → Network → Mock Responses</strong> — manage rules.</li></ul><h3 id="behavior-1" tabindex="-1">Behavior <a class="header-anchor" href="#behavior-1" aria-label="Permalink to &quot;Behavior&quot;">​</a></h3><p>If mock matches:</p><ul><li>the real request is not sent;</li><li>breakpoint does not apply for that call.</li></ul><p>Order of evaluation:</p><ol><li>mock first;</li><li>if no mock — breakpoint;</li><li>otherwise normal network.</li></ol><p>Mock wins over breakpoint.</p><hr><h2 id="breakpoint-vs-mock" tabindex="-1">Breakpoint vs mock <a class="header-anchor" href="#breakpoint-vs-mock" aria-label="Permalink to &quot;Breakpoint vs mock&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Mechanism</th><th>Network round-trip</th><th>Can change request</th><th>Can change response</th></tr></thead><tbody><tr><td>Breakpoint</td><td>Yes</td><td>Yes</td><td>No</td></tr><tr><td>Mock response</td><td>No</td><td>No</td><td>Yes</td></tr></tbody></table><hr><h2 id="limits" tabindex="-1">Limits <a class="header-anchor" href="#limits" aria-label="Permalink to &quot;Limits&quot;">​</a></h2><p>Both work only for:</p><ul><li><strong>fetch</strong></li><li><strong>XMLHttpRequest</strong></li></ul><p>Not intercepted:</p><ul><li><code>&lt;img&gt;</code>, <code>&lt;script&gt;</code>, <code>&lt;link&gt;</code> loads;</li><li>service workers outside this layer;</li><li>native browser calls outside page JS.</li></ul><p><strong>OPTIONS (preflight)</strong> requests are not part of interception.</p><hr><h2 id="compared-to-charles-proxy" tabindex="-1">Compared to Charles Proxy <a class="header-anchor" href="#compared-to-charles-proxy" aria-label="Permalink to &quot;Compared to Charles Proxy&quot;">​</a></h2><p><strong>Charles</strong> (and similar <strong>system / external proxies</strong>: Fiddler, mitmproxy, …) sits <strong>between client and server</strong> at the OS or app level:</p><ul><li>sees traffic <strong>beyond the browser</strong> (mobile apps, CLI, other tools if proxied);</li><li><strong>HTTPS</strong> typically needs a trusted root and <strong>SSL Proxying</strong> (TLS termination);</li><li><strong>Breakpoints</strong> and <strong>Map Local / Remote</strong> apply to <strong>all</strong> matching connections <strong>on that channel</strong>.</li></ul><p><strong>Vue Inspector</strong> runs <strong>inside the browser tab</strong>: it patches <strong><code>fetch</code></strong> and <strong><code>XMLHttpRequest</code></strong>.</p><table tabindex="0"><thead><tr><th>Aspect</th><th>Charles (typical)</th><th>Vue Inspector</th></tr></thead><tbody><tr><td>Level</td><td>Proxy / out-of-process</td><td>JS in the page</td></tr><tr><td>Scope</td><td>Many clients, HTTP(S) through proxy</td><td>This document only: <strong>fetch</strong> and <strong>XHR</strong></td></tr><tr><td>HTTPS</td><td>Custom trust, TLS break</td><td>No extra TLS break — the app already sees responses in JS</td></tr><tr><td>SW / native requests</td><td>Often visible on the path</td><td>Not covered here</td></tr><tr><td>SPA convenience</td><td>Proxy + certs setup</td><td>Enable rules in the inspector for the current site</td></tr></tbody></table><p>In <strong>intent</strong>, Inspector breakpoints/mocks resemble Charles (<strong>pause / fake a response</strong>); in <strong>placement</strong> it is a <strong>page-level devtool</strong>, not a network proxy.</p><h2 id="see-also" tabindex="-1">See also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See also&quot;">​</a></h2><ul><li><a href="/docs/network/general.html">Working with requests</a></li><li><a href="/docs/network/export.html">Export collections</a></li></ul>',56)])])}const g=t(s,[["render",n]]);export{u as __pageData,g as default};
